const winston = require('winston');
const { format } = winston;

// Custom format to sanitize log messages and prevent injection
const sanitizeFormat = format((info) => {
  // Sanitize all string values in the log object
  const sanitize = (value) => {
    if (typeof value !== 'string') return value;

    return value
      // Remove CRLF sequences
      .replace(/[\r\n]+/g, ' ')
      // Escape JNDI lookup patterns (Log4Shell prevention)
      .replace(/\$\{jndi:/gi, '${jndi-blocked:')
      // Remove other control characters
      .replace(/[\x00-\x1F\x7F]/g, '')
      // Limit length to prevent log flooding
      .substring(0, 1000);
  };

  // Recursively sanitize all string properties
  const sanitizeObject = (obj) => {
    if (typeof obj === 'string') return sanitize(obj);
    if (typeof obj !== 'object' || obj === null) return obj;

    const sanitized = Array.isArray(obj) ? [] : {};
    for (const key in obj) {
      sanitized[key] = sanitizeObject(obj[key]);
    }
    return sanitized;
  };

  return sanitizeObject(info);
});

// Custom format to mask sensitive data (PII)
const maskSensitiveData = format((info) => {
  const patterns = {
    password: /"password"\s*:\s*"[^"]+"/gi,
    token: /"token"\s*:\s*"[^"]+"/gi,
    apiKey: /"api[_-]?key"\s*:\s*"[^"]+"/gi,
    email: /(\w+)@(\w+\.\w+)/gi,
    ssn: /\b\d{3}-\d{2}-\d{4}\b/g,
    creditCard: /\b\d{4}[\s-]?\d{4}[\s-]?\d{4}[\s-]?\d{4}\b/g
  };

  if (info.message) {
    Object.entries(patterns).forEach(([key, pattern]) => {
      info.message = info.message.replace(pattern, (match) => {
        if (key === 'email') {
          return match.replace(/^(\w{2})\w+(@\w+)/, '$1***$2');
        }
        return `[${key.toUpperCase()}_REDACTED]`;
      });
    });
  }

  return info;
});

// Create secure logger instance
const logger = winston.createLogger({
  level: process.env.LOG_LEVEL || 'info',
  format: format.combine(
    format.timestamp({ format: 'YYYY-MM-DD HH:mm:ss' }),
    sanitizeFormat(),
    maskSensitiveData(),
    format.errors({ stack: true }),
    format.json() // Use JSON format to prevent log line injection
  ),
  defaultMeta: { service: 'express-api' },
  transports: [
    new winston.transports.File({ 
      filename: 'logs/error.log', 
      level: 'error',
      maxsize: 10485760, // 10MB
      maxFiles: 5
    }),
    new winston.transports.File({ 
      filename: 'logs/combined.log',
      maxsize: 10485760,
      maxFiles: 10
    })
  ]
});

// Add console transport for development
if (process.env.NODE_ENV !== 'production') {
  logger.add(new winston.transports.Console({
    format: format.combine(
      format.colorize(),
      format.simple()
    )
  }));
}

// Express middleware for request logging
const requestLogger = (req, res, next) => {
  const start = Date.now();

  res.on('finish', () => {
    const duration = Date.now() - start;
    logger.info('HTTP Request', {
      method: req.method,
      url: req.url,
      status: res.statusCode,
      duration: `${duration}ms`,
      ip: req.ip,
      userAgent: req.get('user-agent')?.substring(0, 200),
      userId: req.user?.id // Will be sanitized automatically
    });
  });

  next();
};

