# Detect log injection with newline characters in HTTP requests
GET /logs-*/_search
{
  "query": {
    "bool": {
      "should": [
        { "wildcard": { "http.request.body.content": "*\\n*" }},
        { "wildcard": { "http.request.body.content": "*\\r*" }},
        { "wildcard": { "url.query": "*%0a*" }},
        { "wildcard": { "url.query": "*%0d*" }},
        { "match": { "message": "${jndi:" }}
      ],
      "minimum_should_match": 1,
      "filter": [
        { "range": { "@timestamp": { "gte": "now-24h" }}}
      ]
    }
  },
  "aggs": {
    "by_source_ip": {
      "terms": {
        "field": "source.ip",
        "size": 100
      },
      "aggs": {
        "injection_count": {
          "value_count": { "field": "_id" }
        }
      }
    }
  }
}

